<?php namespace App\Mail; use Illuminate\Bus\Queueable; use Illuminate\Mail\Mailable; use Illuminate\Mail\Mailables\Content; use Illuminate\Mail\Mailables\Envelope; use Illuminate\Mail\Mailables\Address; use Illuminate\Queue\SerializesModels; use App\Models\User; use App\Models\Company; class GenericBulkEmail extends Mailable { use Queueable, SerializesModels; public $subject; public $body; public $user; public $company; public function __construct($subject, $body, User $user = null, Company $company = null) { $this->subject = $subject; $this->body = $body; $this->user = $user; $this->company = $company; } public function envelope(): Envelope { $envelope = new Envelope(subject: $this->subject); if ($this->user) { $envelope->replyTo = [new Address($this->user->email, $this->user->name)]; } return $envelope; } public function content(): Content { return new Content(markdown: "emails.generic-bulk-email", with: ["body" => $this->body, "user" => $this->user, "company" => $this->company]); } public function attachments(): array { return []; } }
